import { type MouseEvent as ReactMouseEvent, type ReactNode } from 'react';
import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
/**
 * The marker brightness state
 * @internal
 */
export type MarkerInteractionState = 'default' | 'hovered' | 'active' | 'inactive';
/**
 * Options for text overflow handling in markers
 * @public
 */
export type TextOverflowOptions = 'expand' | 'truncate';
/**
 * @internal
 * Props for MarkerAtom, representing properties related to a marker.
 */
export type MarkerAtomProps = {
    /** X-coordinate of the marker. */
    x: number;
    /** Width of the marker. */
    width: number;
    /** Color of the marker. */
    color: string;
    /** Text overflow handling option. */
    textOverflow: TextOverflowOptions;
    /** Truncation mode for text overflow. */
    truncateMode?: TruncationMode;
    /** Optional callback when the mouse enters the marker. */
    onMouseEnter?: (event: ReactMouseEvent) => void;
    /** Optional callback when the mouse moves inside the marker. */
    onMouseMove?: (event: ReactMouseEvent) => void;
    /** Optional callback when the mouse leaves the marker. */
    onMouseLeave?: (event: ReactMouseEvent) => void;
    /** Optional callback when mouse click inside  the marker. */
    onClick?: (event: ReactMouseEvent) => void;
    /** The content to be rendered inside the marker  */
    content?: ReactNode;
    /** The color to be applied to the content  */
    contentColor?: string;
    /**
     * Current marker state
     * @defaultValue 'default'
     */
    interactionState?: MarkerInteractionState;
};
